import { fileURLToPath } from "url";
import { createVitestNestedHooksAdapter } from "./helpers/qunit-hooks-adapter";
import { describe, it, expect } from "vitest";
import { join, dirname } from 'path';
import type { PgAdapter } from '@cardstack/postgres';
import type { User } from '@cardstack/runtime-common';
import { query, insert, asExpressions } from '@cardstack/runtime-common';
import { setupDB, insertUser, runTestRealmServer, createVirtualNetwork, matrixURL, closeServer, } from './helpers';
import type { RealmServerTokenClaim } from '../utils/jwt';
import { createJWT as createRealmServerJWT } from '../utils/jwt';
import { realmSecretSeed } from './helpers';
import type { SuperTest, Test } from 'supertest';
import supertest from 'supertest';
import type { Server } from 'http';
import { dirSync, type DirResult } from 'tmp';
import { copySync, ensureDirSync } from 'fs-extra';
const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
const testRealmURL = new URL('http://127.0.0.1:0/test/');
describe("boxel-domain-availability-test.ts", function () {
    describe('boxel domain availability endpoint', function () {
        const hooks = createVitestNestedHooksAdapter() as any;
        let testRealmServer: Server;
        let request: SuperTest<Test>;
        let dir: DirResult;
        let dbAdapter: PgAdapter;
        let user: User;
        let boxelSiteDomain = 'boxel.site';
        let defaultToken: RealmServerTokenClaim;
        hooks.beforeEach(async function () {
            dir = dirSync();
        });
        setupDB(hooks, {
            beforeEach: async (_dbAdapter, publisher, runner) => {
                dbAdapter = _dbAdapter;
                let testRealmDir = join(dir.name, 'realm_server_5', 'test');
                ensureDirSync(testRealmDir);
                copySync(join(__dirname, 'cards'), testRealmDir);
                testRealmServer = (await runTestRealmServer({
                    virtualNetwork: createVirtualNetwork(),
                    testRealmDir,
                    realmsRootPath: join(dir.name, 'realm_server_5'),
                    realmURL: testRealmURL,
                    dbAdapter,
                    publisher,
                    runner,
                    matrixURL,
                    domainsForPublishedRealms: { boxelSite: boxelSiteDomain },
                })).testRealmHttpServer;
                request = supertest(testRealmServer);
                user = await insertUser(dbAdapter, 'matrix-user-id', 'test-user', 'test-user@example.com');
                defaultToken = {
                    user: 'matrix-user-id',
                    sessionRoom: 'test-session',
                };
            },
            afterEach: async () => {
                await closeServer(testRealmServer);
            },
        });
        async function makeCheckBoxelDomainRequest(token: RealmServerTokenClaim | null, subdomain?: string) {
            let requestBuilder = request
                .get('/_check-boxel-domain-availability')
                .set('Accept', 'application/json');
            if (token) {
                const jwt = createRealmServerJWT(token, realmSecretSeed);
                requestBuilder = requestBuilder.set('Authorization', `Bearer ${jwt}`);
            }
            if (subdomain !== undefined) {
                requestBuilder = requestBuilder.query({ subdomain });
            }
            return await requestBuilder;
        }
        it('should return 422 when subdomain is missing', async function () {
            const response = await makeCheckBoxelDomainRequest(defaultToken);
            expect(response.status).toBe(422);
            expect(response.text.includes('subdomain query parameter is required')).toBeTruthy();
        });
        it('should return 200 with error for invalid subdomains', async function () {
            const invalidSubdomains = [
                'api',
                'admin',
                'test',
                'api-v2',
                'v1',
                '123',
                'my-api',
                'test-admin',
                'app-test',
                '',
                'a',
                'a'.repeat(64),
                'test@domain',
                'test.domain',
                '-test',
                'test-',
                'MyApp',
                'TEST',
                // Punycode/homoglyph attack protection
                'xn--test',
                'xn--example-123',
                'tëst', // non-ASCII character
                'test™', // trademark symbol
                'tеst', // Cyrillic 'e' (homoglyph)
            ];
            for (const subdomain of invalidSubdomains) {
                const response = await makeCheckBoxelDomainRequest(defaultToken, subdomain);
                expect(response.status).toBe(200);
                const responseBody = response.body;
                expect(responseBody.available).toBe(false);
                expect(responseBody.error).toBeTruthy();
            }
        });
        it('should return 200 with available=true for valid unclaimed subdomains', async function () {
            const validSubdomains = ['mike', 'my-company'];
            for (const subdomain of validSubdomains) {
                const response = await makeCheckBoxelDomainRequest(defaultToken, subdomain);
                expect(response.status).toBe(200);
                const responseBody = response.body;
                expect(responseBody).toBeTruthy();
                expect(responseBody.available).toBe(true);
                expect(responseBody.error).toBe(undefined);
                expect(responseBody.hostname).toBeTruthy();
                expect(responseBody.hostname.includes(subdomain)).toBeTruthy();
            }
        });
        it('should return 200 with available=false for claimed subdomains', async function () {
            const subdomain = 'claimed-site';
            const hostname = `${subdomain}.${boxelSiteDomain}`;
            let { valueExpressions, nameExpressions: nameExpressions } = asExpressions({
                user_id: user.id,
                source_realm_url: `https://${boxelSiteDomain}/test-realm`,
                hostname: hostname,
                claimed_at: Math.floor(Date.now() / 1000),
            });
            await query(dbAdapter, insert('claimed_domains_for_sites', nameExpressions, valueExpressions));
            const response = await makeCheckBoxelDomainRequest(defaultToken, subdomain);
            expect(response.status).toBe(200);
            const responseBody = response.body;
            expect(responseBody).toBeTruthy();
            expect(responseBody.available).toBe(false);
            expect(responseBody.error).toBe(undefined);
            expect(responseBody.hostname).toBe(hostname);
        });
        it('should return available=true for removed/unclaimed subdomains', async function () {
            const subdomain = 'removed-site';
            const hostname = `${subdomain}.${boxelSiteDomain}`;
            // Insert a claimed domain that has been removed
            let { valueExpressions, nameExpressions } = asExpressions({
                user_id: user.id,
                source_realm_url: `https://${boxelSiteDomain}/test-realm`,
                hostname: hostname,
                claimed_at: Math.floor(Date.now() / 1000) - 86400, // claimed yesterday
                removed_at: Math.floor(Date.now() / 1000), // removed now
            });
            await query(dbAdapter, insert('claimed_domains_for_sites', nameExpressions, valueExpressions));
            const response = await makeCheckBoxelDomainRequest(defaultToken, subdomain);
            expect(response.status).toBe(200);
            const responseBody = response.body;
            expect(responseBody).toBeTruthy();
            expect(responseBody.available).toBe(true);
            expect(responseBody.error).toBe(undefined);
            expect(responseBody.hostname.includes(subdomain)).toBeTruthy();
        });
    });
});
